## DungeonGenerator.gd
## Deterministic procedural dungeon generator for Godot 4.
## Uses FastNoiseLite for base terrain, then carves rectangular rooms
## and connects them with L-shaped corridors.
class_name DungeonGenerator
extends Node

# ---------------------------------------------------------------------------
# Exported properties
# ---------------------------------------------------------------------------
@export var seed: int = 12345
@export var width: int = 64
@export var height: int = 64
@export var wall_threshold: float = 0.0

# ---------------------------------------------------------------------------
# Source IDs (must match dungeon.tres)
# ---------------------------------------------------------------------------
const SOURCE_FLOOR: int = 0
const SOURCE_WALL:  int = 1
const SOURCE_DOOR:  int = 2

# Atlas coords: every atlas source has only one tile at (0,0)
const ATLAS_ORIGIN := Vector2i(0, 0)

# ---------------------------------------------------------------------------
# Internal state
# ---------------------------------------------------------------------------
var _rooms: Array[Rect2i] = []

# ---------------------------------------------------------------------------
# Public API
# ---------------------------------------------------------------------------

## Clears *target*, writes noise-based floor/wall, carves rooms & corridors.
func generate(target: TileMapLayer) -> void:
	_rooms.clear()
	target.clear()

	# --- 1. Noise pass ---
	var noise := FastNoiseLite.new()
	noise.noise_type = FastNoiseLite.TYPE_PERLIN
	noise.seed = seed
	noise.frequency = 0.1

	for y in range(height):
		for x in range(width):
			var coords := Vector2i(x, y)
			# Edge cells are always walls
			if x == 0 or x == width - 1 or y == 0 or y == height - 1:
				target.set_cell(coords, SOURCE_WALL, ATLAS_ORIGIN)
			else:
				var v: float = noise.get_noise_2d(float(x), float(y))
				if v > wall_threshold:
					target.set_cell(coords, SOURCE_FLOOR, ATLAS_ORIGIN)
				else:
					target.set_cell(coords, SOURCE_WALL, ATLAS_ORIGIN)

	# --- 2. Room placement (deterministic via seeded RNG) ---
	var rng := RandomNumberGenerator.new()
	rng.seed = seed

	# Attempt to place MIN_ROOMS rooms; retry on overlap up to MAX_TRIES times.
	const MIN_ROOMS: int = 3
	const MAX_TRIES: int = 200
	const ROOM_MIN_W: int = 4
	const ROOM_MAX_W: int = 10
	const ROOM_MIN_H: int = 4
	const ROOM_MAX_H: int = 8

	var placed: Array[Rect2i] = []
	var tries: int = 0
	while placed.size() < MIN_ROOMS and tries < MAX_TRIES:
		tries += 1
		var rw: int = rng.randi_range(ROOM_MIN_W, ROOM_MAX_W)
		var rh: int = rng.randi_range(ROOM_MIN_H, ROOM_MAX_H)
		# Rooms must stay strictly inside the border (1 .. width-2, 1 .. height-2)
		var rx: int = rng.randi_range(1, width  - 2 - rw)
		var ry: int = rng.randi_range(1, height - 2 - rh)
		var candidate := Rect2i(rx, ry, rw, rh)

		# Reject if it overlaps any already-placed room (include 1-cell margin)
		var overlap := false
		for existing in placed:
			var margin := existing.grow(1)
			if margin.intersects(candidate):
				overlap = true
				break
		if overlap:
			continue

		# Carve the room
		_carve_rect(target, candidate)
		placed.append(candidate)

	_rooms = placed

	# --- 3. Connect rooms with L-shaped corridors ---
	# Connect each consecutive pair of rooms centre-to-centre.
	for i in range(placed.size() - 1):
		var a: Rect2i = placed[i]
		var b: Rect2i = placed[i + 1]
		var ca := a.get_center()
		var cb := b.get_center()
		_carve_corridor(target, ca, cb)


## Returns the number of cells with source_id == SOURCE_FLOOR on *target*.
func count_floor_tiles(target: TileMapLayer) -> int:
	var count: int = 0
	for y in range(height):
		for x in range(width):
			if target.get_cell_source_id(Vector2i(x, y)) == SOURCE_FLOOR:
				count += 1
	return count


## Returns the room rectangles carved by the most recent generate() call.
func find_rooms() -> Array[Rect2i]:
	return _rooms.duplicate()


# ---------------------------------------------------------------------------
# Private helpers
# ---------------------------------------------------------------------------

## Overwrites every cell in *rect* with floor tiles.
func _carve_rect(target: TileMapLayer, rect: Rect2i) -> void:
	for y in range(rect.position.y, rect.position.y + rect.size.y):
		for x in range(rect.position.x, rect.position.x + rect.size.x):
			target.set_cell(Vector2i(x, y), SOURCE_FLOOR, ATLAS_ORIGIN)


## Carves an L-shaped corridor from *from_pt* to *to_pt*:
## first horizontal then vertical (or vice-versa, also deterministic).
func _carve_corridor(target: TileMapLayer, from_pt: Vector2i, to_pt: Vector2i) -> void:
	# Horizontal segment
	var x_start: int = min(from_pt.x, to_pt.x)
	var x_end:   int = max(from_pt.x, to_pt.x)
	for x in range(x_start, x_end + 1):
		var coords := Vector2i(x, from_pt.y)
		if _in_interior(coords):
			target.set_cell(coords, SOURCE_FLOOR, ATLAS_ORIGIN)

	# Vertical segment
	var y_start: int = min(from_pt.y, to_pt.y)
	var y_end:   int = max(from_pt.y, to_pt.y)
	for y in range(y_start, y_end + 1):
		var coords := Vector2i(to_pt.x, y)
		if _in_interior(coords):
			target.set_cell(coords, SOURCE_FLOOR, ATLAS_ORIGIN)


## Returns true when *coords* is strictly inside the border ring.
func _in_interior(coords: Vector2i) -> bool:
	return coords.x > 0 and coords.x < width - 1 \
		and coords.y > 0 and coords.y < height - 1

## Verify.gd – headless verification harness for the DungeonGenerator.
## Run with: godot --headless --path . --script res://scripts/Verify.gd
extends SceneTree

func _init() -> void:
	var passed := 0
	var failed := 0

	# -----------------------------------------------------------------------
	# Helper
	# -----------------------------------------------------------------------
	func _ok(label: String) -> void:
		print("[PASS] " + label)
		passed += 1

	func _fail(label: String, detail: String = "") -> void:
		print("[FAIL] " + label + ((" — " + detail) if detail else ""))
		failed += 1

	# -----------------------------------------------------------------------
	# 1. TileSet loads and exposes source_ids 0, 1, 2
	# -----------------------------------------------------------------------
	var ts: TileSet = load("res://tilesets/dungeon.tres")
	if ts == null:
		_fail("TileSet loads")
	else:
		_ok("TileSet loads")
		for sid in [0, 1, 2]:
			if ts.has_source(sid):
				_ok("TileSet has source_id %d" % sid)
			else:
				_fail("TileSet has source_id %d" % sid)

	# -----------------------------------------------------------------------
	# 2. DungeonGenerator can be instantiated
	# -----------------------------------------------------------------------
	var gen_script: GDScript = load("res://scripts/DungeonGenerator.gd")
	var gen: Node = gen_script.new()
	if gen == null:
		_fail("DungeonGenerator instantiates")
		quit(1)
		return
	_ok("DungeonGenerator instantiates")

	# -----------------------------------------------------------------------
	# 3. @export properties exist with defaults
	# -----------------------------------------------------------------------
	assert(gen.get("seed") == 12345,   "default seed")
	assert(gen.get("width") == 64,     "default width")
	assert(gen.get("height") == 64,    "default height")
	assert(gen.get("wall_threshold") == 0.0, "default wall_threshold")
	_ok("@export defaults correct")

	# -----------------------------------------------------------------------
	# 4. generate() runs on a fresh TileMapLayer
	# -----------------------------------------------------------------------
	var layer := TileMapLayer.new()
	layer.tile_set = ts
	get_root().add_child(layer)
	gen.generate(layer)
	_ok("generate() executed without error")

	# -----------------------------------------------------------------------
	# 5. Edge cells are walls
	# -----------------------------------------------------------------------
	var W: int = gen.width
	var H: int = gen.height
	var edge_ok := true
	for x in range(W):
		for y in [0, H - 1]:
			if layer.get_cell_source_id(Vector2i(x, y)) != 1:
				edge_ok = false
				break
	for y in range(H):
		for x in [0, W - 1]:
			if layer.get_cell_source_id(Vector2i(x, y)) != 1:
				edge_ok = false
				break
	if edge_ok:
		_ok("Edge cells are all walls (source_id 1)")
	else:
		_fail("Edge cells are all walls (source_id 1)")

	# -----------------------------------------------------------------------
	# 6. find_rooms() returns >= 3 non-overlapping rooms inside interior
	# -----------------------------------------------------------------------
	var rooms: Array[Rect2i] = gen.find_rooms()
	if rooms.size() >= 3:
		_ok("find_rooms() returns >= 3 rooms (got %d)" % rooms.size())
	else:
		_fail("find_rooms() returns >= 3 rooms", "got %d" % rooms.size())

	var interior := Rect2i(1, 1, W - 2, H - 2)
	var rooms_valid := true
	for i in range(rooms.size()):
		if not interior.encloses(rooms[i]):
			rooms_valid = false
			_fail("Room %d fully inside interior" % i,
				  "room=%s interior=%s" % [str(rooms[i]), str(interior)])
		for j in range(i + 1, rooms.size()):
			if rooms[i].intersects(rooms[j]):
				rooms_valid = false
				_fail("Rooms %d and %d do not overlap" % [i, j])
	if rooms_valid:
		_ok("All rooms inside interior and non-overlapping")

	# -----------------------------------------------------------------------
	# 7. count_floor_tiles >= sum of room areas
	# -----------------------------------------------------------------------
	var floor_count: int = gen.count_floor_tiles(layer)
	var room_area_sum: int = 0
	for r in rooms:
		room_area_sum += r.size.x * r.size.y
	if floor_count >= room_area_sum:
		_ok("count_floor_tiles (%d) >= room area sum (%d)" % [floor_count, room_area_sum])
	else:
		_fail("count_floor_tiles (%d) >= room area sum (%d)" % [floor_count, room_area_sum])

	# -----------------------------------------------------------------------
	# 8. Determinism: two generate() calls with same seed produce same data
	# -----------------------------------------------------------------------
	func _hash_layer(l: TileMapLayer, w: int, h: int) -> int:
		var s: int = 0
		for y in range(h):
			for x in range(w):
				var sid := l.get_cell_source_id(Vector2i(x, y))
				s = (s * 31 + x * 100003 + y * 700001 + sid * 997) & 0x7FFFFFFFFFFFFFFF
		return s

	var hash1 := _hash_layer(layer, W, H)

	var layer2 := TileMapLayer.new()
	layer2.tile_set = ts
	get_root().add_child(layer2)
	gen.generate(layer2)
	var hash2 := _hash_layer(layer2, W, H)

	if hash1 == hash2:
		_ok("Determinism: two runs with seed=12345 produce identical layout (hash=%d)" % hash1)
	else:
		_fail("Determinism: same seed should produce same layout", "hash1=%d hash2=%d" % [hash1, hash2])

	# -----------------------------------------------------------------------
	# 9. Different seed produces different data
	# -----------------------------------------------------------------------
	var gen2: Node = gen_script.new()
	gen2.seed = 99
	var layer3 := TileMapLayer.new()
	layer3.tile_set = ts
	get_root().add_child(layer3)
	gen2.generate(layer3)
	var hash3 := _hash_layer(layer3, W, H)

	if hash3 != hash1:
		_ok("Different seed (99) produces different layout")
	else:
		_fail("Different seed (99) produces different layout", "hashes unexpectedly equal")

	# -----------------------------------------------------------------------
	# Summary
	# -----------------------------------------------------------------------
	print("")
	print("Results: %d passed, %d failed" % [passed, failed])
	quit(0 if failed == 0 else 1)

## Verify.gd – headless acceptance-criteria harness for DungeonGenerator.
## Run with: godot --headless --path . --script res://scripts/Verify.gd
extends SceneTree

var _passed := 0
var _failed := 0

func _ok(label: String) -> void:
	print("[PASS] " + label)
	_passed += 1

func _fail(label: String, detail: String = "") -> void:
	print("[FAIL] " + label + ((" — " + detail) if detail else ""))
	_failed += 1

func _hash_layer(l: TileMapLayer, w: int, h: int) -> int:
	var s: int = 0
	for y in range(h):
		for x in range(w):
			var sid := l.get_cell_source_id(Vector2i(x, y))
			s = (s * 31 + x * 100003 + y * 700001 + sid * 997) & 0x7FFFFFFFFFFFFFFF
	return s

func _init() -> void:
	# -----------------------------------------------------------------------
	# 1. TileSet loads and exposes source_ids 0, 1, 2
	# -----------------------------------------------------------------------
	var ts: TileSet = load("res://tilesets/dungeon.tres")
	if ts == null:
		_fail("TileSet loads")
	else:
		_ok("TileSet loads")
		for sid in [0, 1, 2]:
			if ts.has_source(sid):
				_ok("TileSet has source_id %d" % sid)
			else:
				_fail("TileSet has source_id %d" % sid)

	# -----------------------------------------------------------------------
	# 2. DungeonGenerator can be instantiated
	# -----------------------------------------------------------------------
	var gen_script: GDScript = load("res://scripts/DungeonGenerator.gd")
	var gen: Node = gen_script.new()
	if gen == null:
		_fail("DungeonGenerator instantiates")
		quit(1)
		return
	_ok("DungeonGenerator instantiates")

	# -----------------------------------------------------------------------
	# 3. @export properties exist with defaults
	# -----------------------------------------------------------------------
	var props_ok := true
	if gen.get("seed") != 12345:        props_ok = false
	if gen.get("width") != 64:          props_ok = false
	if gen.get("height") != 64:         props_ok = false
	if gen.get("wall_threshold") != 0.0: props_ok = false
	if props_ok:
		_ok("@export defaults correct (seed=12345, width=64, height=64, wall_threshold=0.0)")
	else:
		_fail("@export defaults", "seed=%s width=%s height=%s threshold=%s" % [
			str(gen.get("seed")), str(gen.get("width")),
			str(gen.get("height")), str(gen.get("wall_threshold"))])

	# -----------------------------------------------------------------------
	# 4. generate() runs on a fresh TileMapLayer
	# -----------------------------------------------------------------------
	var layer := TileMapLayer.new()
	layer.tile_set = ts
	get_root().add_child(layer)
	gen.generate(layer)
	_ok("generate() executed without error")

	# -----------------------------------------------------------------------
	# 5. Edge cells are walls
	# -----------------------------------------------------------------------
	var W: int = gen.width
	var H: int = gen.height
	var edge_ok := true
	for x in range(W):
		if layer.get_cell_source_id(Vector2i(x, 0)) != 1:
			edge_ok = false
		if layer.get_cell_source_id(Vector2i(x, H - 1)) != 1:
			edge_ok = false
	for y in range(H):
		if layer.get_cell_source_id(Vector2i(0, y)) != 1:
			edge_ok = false
		if layer.get_cell_source_id(Vector2i(W - 1, y)) != 1:
			edge_ok = false
	if edge_ok:
		_ok("Edge cells are all walls (source_id=1)")
	else:
		_fail("Edge cells are all walls (source_id=1)")

	# -----------------------------------------------------------------------
	# 6. find_rooms() returns >= 3 non-overlapping rooms inside interior
	# -----------------------------------------------------------------------
	var rooms: Array[Rect2i] = gen.find_rooms()
	if rooms.size() >= 3:
		_ok("find_rooms() returns >= 3 rooms (got %d)" % rooms.size())
	else:
		_fail("find_rooms() returns >= 3 rooms", "got %d" % rooms.size())

	var interior := Rect2i(1, 1, W - 2, H - 2)
	var rooms_valid := true
	for i in range(rooms.size()):
		if not interior.encloses(rooms[i]):
			rooms_valid = false
			_fail("Room %d not inside interior" % i,
				  "room=%s interior=%s" % [str(rooms[i]), str(interior)])
		for j in range(i + 1, rooms.size()):
			if rooms[i].intersects(rooms[j]):
				rooms_valid = false
				_fail("Rooms %d and %d overlap" % [i, j])
	if rooms_valid and rooms.size() >= 3:
		_ok("All rooms inside interior and non-overlapping")

	# -----------------------------------------------------------------------
	# 7. count_floor_tiles >= sum of room areas
	# -----------------------------------------------------------------------
	var floor_count: int = gen.count_floor_tiles(layer)
	var room_area_sum: int = 0
	for r in rooms:
		room_area_sum += r.size.x * r.size.y
	if floor_count >= room_area_sum:
		_ok("count_floor_tiles (%d) >= room area sum (%d)" % [floor_count, room_area_sum])
	else:
		_fail("count_floor_tiles < room area sum", "%d < %d" % [floor_count, room_area_sum])

	# -----------------------------------------------------------------------
	# 8. Determinism: two generate() calls with seed=12345 produce same data
	# -----------------------------------------------------------------------
	var hash1 := _hash_layer(layer, W, H)

	var layer2 := TileMapLayer.new()
	layer2.tile_set = ts
	get_root().add_child(layer2)
	gen.generate(layer2)
	var hash2 := _hash_layer(layer2, W, H)

	if hash1 == hash2:
		_ok("Determinism: seed=12345 gives identical layout twice (hash=%d)" % hash1)
	else:
		_fail("Determinism: same seed gave different hashes", "%d vs %d" % [hash1, hash2])

	# -----------------------------------------------------------------------
	# 9. Different seed produces different data
	# -----------------------------------------------------------------------
	var gen2: Node = gen_script.new()
	gen2.seed = 99
	var layer3 := TileMapLayer.new()
	layer3.tile_set = ts
	get_root().add_child(layer3)
	gen2.generate(layer3)
	var hash3 := _hash_layer(layer3, W, H)

	if hash3 != hash1:
		_ok("Different seed (99) produces different layout (hash=%d)" % hash3)
	else:
		_fail("Different seed (99) should produce different layout", "hashes equal: %d" % hash3)

	# -----------------------------------------------------------------------
	# Summary
	# -----------------------------------------------------------------------
	print("")
	print("=== Results: %d passed, %d failed ===" % [_passed, _failed])
	quit(0 if _failed == 0 else 1)
